  1	import * as React from 'react';
  2	import { useSelector, useDispatch } from 'react-redux';
  3	
  4	import { useTranslation } from 'react-i18next';
  5	import {
  6	  getNewSilenceUrl,
  7	  getLegacyObserveState,
  8	  getFetchSilenceUrl,
  9	  usePerspective,
 10	} from '../hooks/usePerspective';
 11	import { Silences } from '../types';
 12	import { MonitoringState } from 'src/reducers/observe';
 13	import { RowFilter } from '@openshift-console/dynamic-plugin-sdk-internal/lib/extensions/console-types';
 14	import {
 15	  AlertSeverity,
 16	  consoleFetchJSON,
 17	  ListPageFilter,
 18	  RowProps,
 19	  Silence,
 20	  SilenceStates,
 21	  TableColumn,
 22	  useActiveNamespace,
 23	  useListPageFilter,
 24	  VirtualizedTable,
 25	} from '@openshift-console/dynamic-plugin-sdk';
 26	import { Helmet } from 'react-helmet';
 27	import { fuzzyCaseInsensitive, refreshSilences, silenceCluster, silenceState } from '../utils';
 28	import * as _ from 'lodash-es';
 29	import { sortable } from '@patternfly/react-table';
 30	import { SelectedSilencesContext, SilenceTableRow, tableSilenceClasses } from './SilencesUtils';
 31	import {
 32	  Button,
 33	  Checkbox,
 34	  Flex,
 35	  FlexItem,
 36	  PageSection,
 37	  PageSectionVariants,
 38	  Alert as PFAlert,
 39	} from '@patternfly/react-core';
 40	import { useBoolean } from '../hooks/useBoolean';
 41	import { Link } from 'react-router-dom';
 42	import { EmptyBox } from '../console/console-shared/src/components/empty-state/EmptyBox';
 43	import withFallback from '../console/console-shared/error/fallbacks/withFallback';
 44	
 45	const SilencesPage_: React.FC = () => {
 46	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
 47	
 48	  const { silencesKey, perspective } = usePerspective();
 49	
 50	  const [selectedSilences, setSelectedSilences] = React.useState(new Set());
 51	  const [errorMessage, setErrorMessage] = React.useState();
 52	
 53	  const {
 54	    data,
 55	    loaded = false,
 56	    loadError,
 57	  }: Silences = useSelector(
 58	    (state: MonitoringState) => getLegacyObserveState(perspective, state)?.get(silencesKey) || {},
 59	  );
 60	
 61	  const clusters = React.useMemo(() => {
 62	    const clusterSet = new Set<string>();
 63	    data?.forEach((silence) => {
 64	      const clusterName = silenceCluster(silence);
 65	      if (clusterName) {
 66	        clusterSet.add(clusterName);
 67	      }
 68	    });
 69	
 70	    const clusterArray = Array.from(clusterSet);
 71	    return clusterArray.sort();
 72	  }, [data]);
 73	
 74	  const rowFilters: RowFilter[] = [
 75	    // TODO: The "name" filter doesn't really fit useListPageFilter's idea of a RowFilter, but
 76	    //       useListPageFilter doesn't yet provide a better way to add a filter like this
 77	    {
 78	      filter: (filter, silence: Silence) =>
 79	        fuzzyCaseInsensitive(filter.selected?.[0], silence.name),
 80	      filterGroupName: '',
 81	      items: [],
 82	      type: 'name',
 83	    } as RowFilter,
 84	    {
 85	      defaultSelected: [SilenceStates.Active, SilenceStates.Pending],
 86	      filter: (filter, silence: Silence) =>
 87	        filter.selected?.includes(silenceState(silence)) || _.isEmpty(filter.selected),
 88	      filterGroupName: t('Silence State'),
 89	      items: [
 90	        { id: SilenceStates.Active, title: t('Active') },
 91	        { id: SilenceStates.Pending, title: t('Pending') },
 92	        { id: SilenceStates.Expired, title: t('Expired') },
 93	      ],
 94	      reducer: silenceState,
 95	      type: 'silence-state',
 96	    },
 97	  ];
 98	
 99	  if (perspective === 'acm') {
100	    rowFilters.splice(-1, 0, {
101	      type: 'silence-cluster',
102	      filter: (filter, silence: Silence) =>
103	        filter.selected.length === 0 ||
104	        filter.selected.some((selectedFilter) =>
105	          fuzzyCaseInsensitive(
106	            selectedFilter,
107	            silence.matchers.find((label) => label.name === 'cluster').value,
108	          ),
109	        ),
110	      filterGroupName: t('Cluster'),
111	      items: clusters.map((clusterName) => ({ id: clusterName, title: clusterName })),
112	      reducer: silenceCluster,
113	      isMatch: (silence: Silence, clusterName: string) =>
114	        fuzzyCaseInsensitive(
115	          clusterName,
116	          silence.matchers.find((label) => label.name === 'cluster').value,
117	        ),
118	    } as RowFilter);
119	  }
120	
121	  const [staticData, filteredData, onFilterChange] = useListPageFilter(data, rowFilters);
122	
123	  const columns = React.useMemo<TableColumn<Silence>[]>(() => {
124	    const cols = [
125	      {
126	        id: 'checkbox',
127	        props: { className: tableSilenceClasses[0] },
128	        title: (<SelectAllCheckbox silences={filteredData} />) as any,
129	      },
130	      {
131	        id: 'name',
132	        props: { className: tableSilenceClasses[1] },
133	        sort: 'name',
134	        title: t('Name'),
135	        transforms: [sortable],
136	      },
137	      {
138	        id: 'firingAlerts',
139	        props: { className: tableSilenceClasses[2] },
140	        sort: (silences: Silence[], direction: 'asc' | 'desc') =>
141	          _.orderBy(silences, silenceFiringAlertsOrder, [direction]),
142	        title: t('Firing alerts'),
143	        transforms: [sortable],
144	      },
145	      {
146	        id: 'state',
147	        props: { className: tableSilenceClasses[3] },
148	        sort: (silences: Silence[], direction: 'asc' | 'desc') =>
149	          _.orderBy(silences, silenceStateOrder, [direction]),
150	        title: t('State'),
151	        transforms: [sortable],
152	      },
153	      {
154	        id: 'createdBy',
155	        props: { className: tableSilenceClasses[4] },
156	        sort: 'createdBy',
157	        title: t('Creator'),
158	        transforms: [sortable],
159	      },
160	      {
161	        id: 'actions',
162	        props: { className: tableSilenceClasses[6] },
163	        title: '',
164	      },
165	    ];
166	
167	    if (perspective === 'acm') {
168	      cols.splice(-1, 0, {
169	        id: 'cluster',
170	        props: { className: tableSilenceClasses[5] },
171	        sort: (silences: Silence[], direction: 'asc' | 'desc') =>
172	          _.orderBy(silences, silenceClusterOrder(clusters), [direction]),
173	        title: t('Cluster'),
174	        transforms: [sortable],
175	      });
176	    }
177	    return cols;
178	  }, [filteredData, t, perspective, clusters]);
179	
180	  return (
181	    <>
182	      <Helmet>{perspective === 'dev' ? <title>Silences</title> : <title>Alerting</title>}</Helmet>
183	      <PageSection variant={PageSectionVariants.light}>
184	        <SelectedSilencesContext.Provider value={{ selectedSilences, setSelectedSilences }}>
185	          <Flex>
186	            <FlexItem>
187	              <ListPageFilter
188	                data={staticData}
189	                hideLabelFilter
190	                loaded={loaded}
191	                onFilterChange={onFilterChange}
192	                rowFilters={rowFilters}
193	              />
194	            </FlexItem>
195	            <FlexItem>
196	              <CreateSilenceButton />
197	            </FlexItem>
198	            <FlexItem>
199	              <ExpireAllSilencesButton setErrorMessage={setErrorMessage} />
200	            </FlexItem>
201	          </Flex>
202	          {loadError && (
203	            <PFAlert
204	              isInline
205	              title={t(
206	                'Error loading silences from Alertmanager. Alertmanager may be unavailable.',
207	              )}
208	              variant="danger"
209	            >
210	              {typeof loadError === 'string' ? loadError : loadError.message}
211	            </PFAlert>
212	          )}
213	          {errorMessage && (
214	            <PFAlert isInline title={t('Error')} variant="danger">
215	              {errorMessage}
216	            </PFAlert>
217	          )}
218	          <VirtualizedTable<Silence>
219	            aria-label={t('Silences')}
220	            label={t('Silences')}
221	            columns={columns}
222	            data={filteredData ?? []}
223	            loaded={loaded}
224	            loadError={loadError}
225	            Row={SilenceTableRowWithCheckbox}
226	            unfilteredData={data}
227	            NoDataEmptyMsg={() => {
228	              return <EmptyBox label={t('Silences')} />;
229	            }}
230	          />
231	        </SelectedSilencesContext.Provider>
232	      </PageSection>
233	    </>
234	  );
235	};
236	const SilencesPage = withFallback(SilencesPage_);
237	
238	const SelectAllCheckbox: React.FC<{ silences: Silence[] }> = ({ silences }) => {
239	  const { selectedSilences, setSelectedSilences } = React.useContext(SelectedSilencesContext);
240	
241	  const activeSilences = _.filter(silences, (s) => silenceState(s) !== SilenceStates.Expired);
242	  const isAllSelected =
243	    activeSilences.length > 0 && _.every(activeSilences, (s) => selectedSilences.has(s.id));
244	
245	  const onChange = React.useCallback(
246	    (isChecked: boolean) => {
247	      const ids = isChecked ? activeSilences.map((s) => s.id) : [];
248	      setSelectedSilences(new Set(ids));
249	    },
250	    [activeSilences, setSelectedSilences],
251	  );
252	
253	  return (
254	    <Checkbox
255	      id="select-all-silences-checkbox"
256	      isChecked={isAllSelected}
257	      isDisabled={activeSilences.length === 0}
258	      onChange={(_e, checked) => (typeof _e === 'boolean' ? onChange(_e) : onChange(checked))}
259	    />
260	  );
261	};
262	
263	const silenceFiringAlertsOrder = (silence: Silence) => {
264	  const counts = _.countBy(silence.firingAlerts, 'labels.severity');
265	  return [
266	    Number.MAX_SAFE_INTEGER - (counts[AlertSeverity.Critical] ?? 0),
267	    Number.MAX_SAFE_INTEGER - (counts[AlertSeverity.Warning] ?? 0),
268	    silence.firingAlerts.length,
269	  ];
270	};
271	
272	const silenceStateOrder = (silence: Silence) => [
273	  [SilenceStates.Active, SilenceStates.Pending, SilenceStates.Expired].indexOf(
274	    silenceState(silence),
275	  ),
276	  _.get(silence, silenceState(silence) === SilenceStates.Pending ? 'startsAt' : 'endsAt'),
277	];
278	
279	const silenceClusterOrder = (clusters: Array<string>) => {
280	  clusters.sort();
281	  return (silence: Silence) => [
282	    clusters.indexOf(silence.matchers.find((label) => label.name === 'cluster')?.value),
283	  ];
284	};
285	
286	const ExpireAllSilencesButton: React.FC<ExpireAllSilencesButtonProps> = ({ setErrorMessage }) => {
287	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
288	
289	  const { perspective, silencesKey } = usePerspective();
290	
291	  const [isInProgress, , setInProgress, setNotInProgress] = useBoolean(false);
292	
293	  const dispatch = useDispatch();
294	
295	  const { selectedSilences, setSelectedSilences } = React.useContext(SelectedSilencesContext);
296	
297	  const [namespace] = useActiveNamespace();
298	
299	  const onClick = () => {
300	    setInProgress();
301	    Promise.allSettled(
302	      [...selectedSilences].map((silenceID: string) =>
303	        consoleFetchJSON.delete(getFetchSilenceUrl(perspective, silenceID, namespace)),
304	      ),
305	    ).then((values) => {
306	      setNotInProgress();
307	      setSelectedSilences(new Set());
308	      refreshSilences(dispatch, perspective, silencesKey);
309	      const errors = values
310	        .filter((v) => v.status === 'rejected')
311	        .map((v: PromiseRejectedResult) => v.reason);
312	      if (errors.length > 0) {
313	        const messages = errors.map(
314	          (err) => _.get(err, 'json.error') || err.message || 'Error expiring silence',
315	        );
316	        setErrorMessage(messages.join(', '));
317	      }
318	    });
319	  };
320	
321	  return (
322	    <Button
323	      isDisabled={selectedSilences.size === 0}
324	      isLoading={isInProgress}
325	      onClick={onClick}
326	      variant="secondary"
327	    >
328	      {t('Expire {{count}} silence', { count: selectedSilences.size })}
329	    </Button>
330	  );
331	};
332	
333	const SilenceTableRowWithCheckbox: React.FC<RowProps<Silence>> = ({ obj }) => (
334	  <SilenceTableRow showCheckbox={true} obj={obj} />
335	);
336	
337	const CreateSilenceButton: React.FC = React.memo(() => {
338	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
339	  const { perspective } = usePerspective();
340	  const [namespace] = useActiveNamespace();
341	
342	  return (
343	    <Link to={getNewSilenceUrl(perspective, namespace)}>
344	      <Button data-test="create-silence-btn" variant="primary">
345	        {t('Create silence')}
346	      </Button>
347	    </Link>
348	  );
349	});
350	
351	export default SilencesPage;
352	
353	type ExpireAllSilencesButtonProps = {
354	  setErrorMessage: (string) => void;
355	};

